from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check mailbox.json"}
    mailbox_path = Path(external_services_path) / "mailbox.json"
    if not mailbox_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "mailbox.json not found"}
    with open(mailbox_path) as f:
        data = json.load(f)
    emails = data.get("emails", [])

    # Find all emails sent TO Claire
    candidates = []
    for e in emails:
        to_addr = e.get("to_addr", "") or ""
        if isinstance(to_addr, list):
            to_str = " ".join(str(a) for a in to_addr).lower()
        else:
            to_str = str(to_addr).lower()
        if "claire" in to_str or "ndubisi" in to_str:
            candidates.append(e)

    if not candidates:
        # Also check for replies that might not have to_addr but have in_reply_to
        claire_msg_ids = set()
        for e in emails:
            from_addr = (e.get("from_addr", "") or "").lower()
            if "claire" in from_addr or "ndubisi" in from_addr:
                msg_id = e.get("message_id")
                if msg_id:
                    claire_msg_ids.add(msg_id)
        if claire_msg_ids:
            candidates = [e for e in emails if e.get("in_reply_to") in claire_msg_ids]

    if not candidates:
        all_to_addrs = [(e.get("email_id", "?"), e.get("to_addr", ""), e.get("from_addr", "")) for e in emails]
        return {"pass": False, "score": 0.0, "feedback": f"No email sent to Claire found. All emails to/from: {all_to_addrs[:20]}"}

    # The rubric requires the email to use the exact FMLA eligibility script from
    # email template #2. We check for key phrases from that template in order.
    key_phrases = [
        r"thank you for submitting your fmla leave request",
        r"(are\s+)?eligible for fmla leave",
        r"eligibility criteria",
        r"(notice of eligibility|wh[\-\s]?381)",
        r"medical certification",
        r"wh[\-\s]?380",
        r"certification.{0,50}due",
        r"leave may be denied",
        r"case\s*id",
        r"ridgeline gear"
    ]

    # Check that Case ID is specifically LC-2026-0050
    case_id_pattern = r"lc[\-\s]?2026[\-\s]?0050"

    # Phrases/topics that indicate additional context beyond the template
    # The rubric specifically says noting additional info like Colorado FAMLI is not allowed
    disallowed_phrases = [
        r"famli",
        r"colorado",
        r"state\s+(leave|benefit|program)",
    ]

    best_match = None
    best_score = 0
    best_details = {}
    best_extra_content_issue = False
    best_case_id_correct = False
    bodies_info = []

    for e in candidates:
        body = (e.get("body_text", "") or e.get("body", "") or "").lower()
        # Normalize whitespace for matching
        body_norm = re.sub(r'\s+', ' ', body)

        matched = []
        missed = []
        for phrase in key_phrases:
            if re.search(phrase, body_norm):
                matched.append(phrase)
            else:
                missed.append(phrase)

        match_score = len(matched)

        # Check case ID specifically
        case_id_correct = bool(re.search(case_id_pattern, body_norm))

        # Check for disallowed extra content
        extra_content_found = []
        for dp in disallowed_phrases:
            if re.search(dp, body_norm):
                extra_content_found.append(dp)

        bodies_info.append({
            "email_id": e.get("email_id"),
            "match_score": match_score,
            "matched": matched,
            "missed": missed,
            "extra_content": extra_content_found,
            "case_id_correct": case_id_correct,
            "body_preview": body[:500]
        })

        if match_score > best_score:
            best_score = match_score
            best_match = e
            best_details = {"matched": matched, "missed": missed, "extra_content": extra_content_found}
            best_extra_content_issue = len(extra_content_found) > 0
            best_case_id_correct = case_id_correct

    total_phrases = len(key_phrases)

    # If best match has disallowed extra content, it fails regardless of key phrase score
    if best_extra_content_issue and best_score >= 8:
        body = (best_match.get("body_text", "") or best_match.get("body", "") or "")
        return {
            "pass": False,
            "score": 0.3,
            "feedback": f"Reply to Claire (email_id={best_match.get('email_id')}) follows the template structure ({best_score}/{total_phrases} key phrases matched), but contains disallowed additional content/modifications: {best_details['extra_content']}. The rubric says 'Noting additional information, like Colorado FAMLI qualifications, is not allowed.' Body preview: {body[:500]}"
        }

    # Strict: require at least 8 out of 10 key phrases for a full pass, no disallowed content, and correct case ID
    if best_score >= 8 and not best_extra_content_issue and best_case_id_correct:
        body = (best_match.get("body_text", "") or best_match.get("body", "") or "")
        return {
            "pass": True,
            "score": 1.0,
            "feedback": f"Reply to Claire (email_id={best_match.get('email_id')}) closely follows email template #2 script ({best_score}/{total_phrases} key phrases matched) without disallowed additional content. Case ID LC-2026-0050 found. Matched: {best_details['matched']}. Body preview: {body[:500]}"
        }

    # If template matches well but case ID is wrong or missing
    if best_score >= 8 and not best_extra_content_issue and not best_case_id_correct:
        body = (best_match.get("body_text", "") or best_match.get("body", "") or "")
        return {
            "pass": False,
            "score": 0.7,
            "feedback": f"Reply to Claire (email_id={best_match.get('email_id')}) follows the template structure ({best_score}/{total_phrases} key phrases matched) but Case ID LC-2026-0050 was not found in the email body. Body preview: {body[:500]}"
        }

    # Partial: 6-7 out of 10 -- the template is mostly there but with some modifications
    if best_score >= 6:
        body = (best_match.get("body_text", "") or best_match.get("body", "") or "")
        extra_note = ""
        if best_extra_content_issue:
            extra_note = f" Also contains disallowed additional content: {best_details['extra_content']}."
        return {
            "pass": False,
            "score": 0.5,
            "feedback": f"Reply to Claire (email_id={best_match.get('email_id')}) partially follows template #2 but not closely enough ({best_score}/{total_phrases} key phrases matched). Matched: {best_details['matched']}. Missed: {best_details['missed']}.{extra_note} Body preview: {body[:500]}"
        }

    return {
        "pass": False,
        "score": 0.0,
        "feedback": f"Reply(s) to Claire found but none adhere to the exact FMLA eligibility template #2 script. Best match scored {best_score}/{total_phrases}. Candidate details: {json.dumps(bodies_info, indent=2)[:2000]}"
    }

from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check mailbox.json"}
    mailbox_path = Path(external_services_path) / "mailbox.json"
    if not mailbox_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "mailbox.json not found"}
    with open(mailbox_path) as f:
        data = json.load(f)
    emails = data.get("emails", [])

    # Find the reply/sent email to Claire regarding FMLA
    candidate_emails = []
    for e in emails:
        # Check all possible recipient fields
        to_addr = (e.get("to_addr", "") or "").lower()
        to_field = (e.get("to", "") or "").lower()
        combined_to = to_addr + " " + to_field

        if "claire" not in combined_to:
            continue

        # Gather text from body, subject, attachments
        body = (e.get("body", "") or "").lower()
        subject = (e.get("subject", "") or "").lower()

        attachments = e.get("attachments", []) or []
        attachment_names = ""
        if isinstance(attachments, list):
            for att in attachments:
                if isinstance(att, str):
                    attachment_names += att.lower() + " "
                elif isinstance(att, dict):
                    attachment_names += (att.get("filename", "") or att.get("name", "") or "").lower() + " "

        combined_text = body + " " + subject + " " + attachment_names

        # Check for FMLA-related content: forms (WH-380, WH-381), or keyword "fmla"
        has_380 = "wh-380" in combined_text or "wh380" in combined_text or "380-f" in combined_text or "380f" in combined_text
        has_381 = "wh-381" in combined_text or "wh381" in combined_text
        has_fmla = "fmla" in combined_text

        if has_380 or has_381 or has_fmla:
            candidate_emails.append(e)

    if not candidate_emails:
        # Fallback: look for any email to Claire around April 9 (check both 2025 and 2026)
        for e in emails:
            to_addr = (e.get("to_addr", "") or "").lower()
            to_field = (e.get("to", "") or "").lower()
            combined_to = to_addr + " " + to_field
            date = (e.get("date", "") or "").lower()
            timestamp = e.get("timestamp", e.get("ts", e.get("time", None)))

            date_match = ("2026-04-09" in date or "2025-04-09" in date or "april 9" in date or "apr 9" in date)
            # Also check timestamp around April 9, 2026 (1775692800 +/- 1 day = 86400)
            ts_match = False
            if timestamp is not None:
                try:
                    ts_val = float(timestamp)
                    if abs(ts_val - 1775692800) < 86400:
                        ts_match = True
                except (ValueError, TypeError):
                    pass

            if "claire" in combined_to and (date_match or ts_match):
                candidate_emails.append(e)

    if not candidate_emails:
        return {"pass": False, "score": 0.0, "feedback": "No FMLA-related email sent to Claire found in mailbox.json"}

    # Check that at least one of the candidate emails is in the FMLA Cases folder
    failures = []
    successes = []
    for e in candidate_emails:
        folder = (e.get("folder", "") or "").strip()
        eid = e.get("email_id", e.get("message_id", e.get("id", "unknown")))
        subject = e.get("subject", "")
        # Be loose: accept any folder containing "fmla" (case-insensitive)
        if "fmla" in folder.lower():
            successes.append(f"Email (id={eid}, subject='{subject}') is in folder '{folder}'")
        else:
            failures.append(f"Email to Claire (id={eid}, subject='{subject}') is in folder '{folder}', expected 'FMLA Cases'")

    if successes:
        return {"pass": True, "score": 1.0, "feedback": f"Found {len(successes)} email(s) to Claire in FMLA Cases folder. " + "; ".join(successes)}

    return {"pass": False, "score": 0.0, "feedback": "Email(s) to Claire regarding FMLA not in FMLA Cases folder: " + "; ".join(failures)}

from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check slack_data.json"}
    slack_path = Path(external_services_path) / "slack_data.json"
    if not slack_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "slack_data.json not found"}
    with open(slack_path) as f:
        data = json.load(f)
    channels = data.get("channels", {})
    leave_intake_id = None
    for cid, ch in channels.items():
        if ch.get("name", "").lower() == "leave-intake":
            leave_intake_id = cid
            break
    if leave_intake_id is None:
        return {"pass": False, "score": 0.0, "feedback": "#leave-intake channel not found in slack_data.json"}
    messages = data.get("messages", {}).get(leave_intake_id, [])

    april_9_start = 1775692800.0 - 86400 * 3
    april_9_end   = 1775692800.0 + 86400 * 4

    def is_around_april_9(ts_val):
        try:
            return april_9_start <= float(ts_val) <= april_9_end
        except (ValueError, TypeError):
            return False

    april_9_msgs = [m for m in messages if is_around_april_9(m.get("ts", 0))]
    candidates = april_9_msgs if april_9_msgs else messages

    def check_message(text):
        t  = text
        tl = text.lower()
        findings = {}
        score = 0.0

        # 1. FMLA INTAKE header
        has_header = bool(re.search(r"fmla\s*intake", tl))
        findings["fmla_intake_header"] = has_header
        if has_header:
            score += 0.1

        # 2. Case ID LC-2026-0050
        has_case_id = bool(re.search(r"LC[\-\s]?2026[\-\s]?0050", t, re.IGNORECASE))
        findings["case_id_LC-2026-0050"] = has_case_id
        if has_case_id:
            score += 0.2

        # 3. Employee name (Claire or Ndubisi)
        has_name = bool(re.search(r"claire|ndubisi", tl))
        findings["employee_name"] = has_name
        if has_name:
            score += 0.1

        # 4. Eligibility — eligib* covers eligible, eligibility, eligibility confirmed, etc.
        has_eligible   = bool(re.search(r"eligib", tl))
        has_ineligible = bool(re.search(r"ineligible|not\s+eligible", tl))
        is_eligible    = has_eligible and not has_ineligible
        findings["eligible"] = is_eligible
        if is_eligible:
            score += 0.2

        # 5. Reason category is family care (not own condition)
        family_patterns = [
            r"family\s*(member|care|caregiver)",
            r"care\s*(for|of)\s*(a\s+)?family",
            r"\(b\)",   # SOP reason code (b) = family member serious health condition
            r"family.*serious",
            r"serious.*family",
            r"mother|father|parent|spouse|domestic\s+partner",
        ]
        own_patterns = [r"own\s*(serious)?\s*condition", r"employee.{0,5}own", r"self[\-\s]care"]
        has_family     = any(re.search(p, tl) for p in family_patterns)
        has_own        = any(re.search(p, tl) for p in own_patterns)
        is_family_care = has_family and not has_own
        findings["family_care_reason"] = is_family_care
        if is_family_care:
            score += 0.2

        # 6. Priority must be P2
        has_p2 = bool(re.search(r"\bP2\b|priority\s*[=:]?\s*2\b", t, re.IGNORECASE))
        findings["priority_P2"] = has_p2
        if has_p2:
            score += 0.2

        return score, findings

    best_score    = 0.0
    best_findings = {}
    best_text     = ""
    best_msg      = None

    for msg in candidates:
        text = msg.get("text", "")
        # Must mention the case ID to be considered
        if "LC-2026-0050" not in text and "lc-2026-0050" not in text.lower():
            continue
        score, findings = check_message(text)
        if score > best_score:
            best_score    = score
            best_findings = findings
            best_text     = text
            best_msg      = msg

    # Fallback: search all messages if nothing found in date window
    if best_msg is None:
        for msg in messages:
            text = msg.get("text", "")
            if "LC-2026-0050" not in text and "lc-2026-0050" not in text.lower():
                continue
            score, findings = check_message(text)
            if score > best_score:
                best_score    = score
                best_findings = findings
                best_text     = text
                best_msg      = msg

    if best_msg is None:
        all_texts = [m.get("text", "")[:80] for m in messages[-5:]]
        return {"pass": False, "score": 0.0, "feedback": f"No message mentioning case LC-2026-0050 found in #leave-intake. Total messages: {len(messages)}. Recent: {all_texts}"}

    required = ["case_id_LC-2026-0050", "eligible", "family_care_reason", "priority_P2"]
    missing  = [k for k in required if not best_findings.get(k, False)]

    if not missing:
        return {"pass": True, "score": 1.0, "feedback": f"FMLA intake message meets all rubric requirements. Findings: {best_findings}. Preview: {best_text[:300]}"}
    else:
        return {"pass": False, "score": round(best_score, 2), "feedback": f"Intake message found but missing: {missing}. Findings: {best_findings}. Preview: {best_text[:300]}"}

