from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check slack_data.json"}
    slack_path = Path(external_services_path) / "slack_data.json"
    if not slack_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "slack_data.json not found"}
    with open(slack_path) as f:
        data = json.load(f)

    # The rubric says April 9, 2026 with reference timestamp 1775692800
    # 1775692800 is 2026-04-09 00:00:00 UTC
    # End of that day: 1775692800 + 86400 - 1 = 1775779199
    april_9_start = 1775692800.0
    april_9_end = 1775779199.0

    em_dash_violations = []
    messages_dict = data.get("messages", {})
    for channel_id, msgs in messages_dict.items():
        if not isinstance(msgs, list):
            continue
        for msg in msgs:
            ts_raw = msg.get("ts", 0)
            try:
                ts = float(ts_raw)
            except (ValueError, TypeError):
                continue
            if april_9_start <= ts <= april_9_end:
                text = msg.get("text", "")
                # Check for em-dash unicode character (\u2014) or triple dash (---)
                if "\u2014" in text or "---" in text:
                    channel_name = channel_id
                    # Try to resolve channel name for better feedback
                    channels = data.get("channels", {})
                    if channel_id in channels:
                        channel_name = channels[channel_id].get("name", channel_id)
                    snippet = text[:120].replace("\n", " ")
                    em_dash_violations.append(f"Channel #{channel_name} (ts={ts_raw}): '{snippet}'")

    if em_dash_violations:
        return {
            "pass": False,
            "score": 0.0,
            "feedback": f"Found {len(em_dash_violations)} message(s) on April 9, 2026 containing em-dashes: " + "; ".join(em_dash_violations)
        }
    return {
        "pass": True,
        "score": 1.0,
        "feedback": "No new messages on April 9, 2026 contain em-dashes (checked for \u2014 and ---)"
    }

from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    mailbox_path = None
    if external_services_path:
        c = Path(external_services_path) / "mailbox.json"
        if c.exists():
            mailbox_path = c
    if not mailbox_path:
        c = Path(workspace_path) / "mailbox.json"
        if c.exists():
            mailbox_path = c
    if not mailbox_path:
        return {"pass": False, "score": 0.0, "feedback": "mailbox.json not found."}

    with open(mailbox_path, "r", encoding="utf-8") as f:
        data = json.load(f)
    emails = data.get("emails", [])

    greg_emails = []
    for e in emails:
        to = (e.get("to_addr") or "").lower()
        if "greg.ostrowski" in to or ("ostrowski" in to and "ridgelinegear" in to):
            greg_emails.append(e)

    if not greg_emails:
        return {"pass": False, "score": 0.0, "feedback": "No email found addressed to greg.ostrowski@ridgelinegear.com."}

    date_patterns = [
        r"april\s*14", r"apr\s*14", r"4[/\-]14", r"04[/\-]14",
        r"2026[/\-]04[/\-]14", r"14[/\-]04", r"14\s+april",
    ]
    category_terms = [
        "fmla", "family and medical leave", "family medical leave",
        "medical leave", "leave of absence", "approved leave",
        "leave request", "leave notification", "leave",
    ]
    medical_leak_terms = [
        "surgery", "cancer", "chemotherapy", "tumor", "diagnosis",
        "diabetes", "heart attack", "cardiac", "stroke", "fracture",
        "depression", "anxiety", "chronic illness", "autoimmune",
        "serious health condition details", "diagnosed with",
        "treatment for", "condition is", "hospitalized for",
    ]

    issues_by_email = []
    for e in greg_emails:
        body    = (e.get("body_text") or "").lower()
        subject = (e.get("subject")   or "").lower()
        folder  = (e.get("folder")    or "").lower()
        full    = subject + " " + body
        issues  = []

        if "fmla" not in folder:
            issues.append(f"filed in '{e.get('folder', '')}' instead of FMLA Cases")

        if "claire" not in full and "ndubisi" not in full:
            issues.append("missing Claire Ndubisi's name")

        if not any(re.search(p, full) for p in date_patterns):
            issues.append("missing leave start date (April 14, 2026)")

        if not any(t in full for t in category_terms):
            issues.append("missing leave category")

        # Strip standard FMLA boilerplate before checking for diagnosis leaks
        cleaned = full
        for phrase in ["family and medical leave act", "family and medical leave",
                       "family medical leave act", "family medical leave", "medical leave"]:
            cleaned = cleaned.replace(phrase, "")
        leaked = [t for t in medical_leak_terms if t in cleaned]
        if leaked:
            issues.append(f"leaks medical reason/diagnosis ({leaked})")

        issues_by_email.append((e, issues))

    passing = [(e, iss) for e, iss in issues_by_email if not iss]
    if passing:
        e = passing[0][0]
        return {"pass": True, "score": 1.0,
                "feedback": f"Found qualifying manager notification to Greg Ostrowski. "
                            f"folder='{e.get('folder')}', subject='{e.get('subject')}'."}

    feedback = "No email to Greg Ostrowski met all criteria. Details: " + " | ".join(
        f"subject='{e.get('subject')}', folder='{e.get('folder')}': {'; '.join(iss)}"
        for e, iss in issues_by_email
    )
    return {"pass": False, "score": 0.0, "feedback": feedback}

from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    # This rubric checks mailbox.json which lives in external_services_path
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot locate mailbox.json to verify email state."}

    mailbox_path = Path(external_services_path) / "mailbox.json"
    if not mailbox_path.exists():
        return {"pass": False, "score": 0.0, "feedback": f"mailbox.json not found at {mailbox_path}"}

    try:
        with open(mailbox_path, "r", encoding="utf-8") as f:
            data = json.load(f)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to parse mailbox.json: {e}"}

    emails = data.get("emails", [])
    if not emails:
        return {"pass": False, "score": 0.0, "feedback": "No emails found in mailbox.json."}

    # Find the email from Claire
    claire_emails = []
    for em in emails:
        from_addr = (em.get("from_addr") or "").strip().lower()
        if "claire.ndubisi@ridgelinegear.com" in from_addr:
            claire_emails.append(em)

    if not claire_emails:
        return {"pass": False, "score": 0.0, "feedback": "No email from claire.ndubisi@ridgelinegear.com found in mailbox.json."}

    # Try to find the specific email (Email 1 / the intake email received April 9 2026)
    # Be generous: check all emails from Claire and see if any matches
    target = None
    for em in claire_emails:
        # Prefer email_id "1" if present
        if str(em.get("email_id", "")).strip() == "1":
            target = em
            break
    # If no email_id 1, just take the first one from Claire (be lenient)
    if target is None:
        target = claire_emails[0]

    is_read = target.get("is_read", False)
    folder = (target.get("folder") or "").strip()

    # Check folder - be flexible with naming
    folder_lower = folder.lower().replace(" ", "").replace("_", "").replace("-", "")
    acceptable_folders = ["fmlacases", "fmla cases", "fmla_cases", "fmla-cases"]
    folder_ok = any(folder_lower == af.lower().replace(" ", "").replace("_", "").replace("-", "") for af in acceptable_folders)

    # Also accept if the folder contains "fmla" and "case" loosely
    if not folder_ok:
        folder_ok = "fmla" in folder_lower and "case" in folder_lower

    issues = []
    if not is_read:
        issues.append(f"Email is_read is {is_read} (expected True).")
    if not folder_ok:
        issues.append(f"Email folder is '{folder}' (expected 'FMLA Cases' or similar).")

    if issues:
        score = 0.0
        # Give partial credit
        if is_read and not folder_ok:
            score = 0.5
        elif folder_ok and not is_read:
            score = 0.5
        return {"pass": False, "score": score, "feedback": "Claire's intake email issues: " + " ".join(issues)}

    return {"pass": True, "score": 1.0, "feedback": f"Claire's intake email (id={target.get('email_id')}) is marked as read (is_read={is_read}) and moved to folder '{folder}'."}

from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check mailbox.json."}

    mailbox_path = Path(external_services_path) / "mailbox.json"
    if not mailbox_path.exists():
        return {"pass": False, "score": 0.0, "feedback": f"mailbox.json not found at {mailbox_path}"}

    with open(mailbox_path, "r", encoding="utf-8") as f:
        data = json.load(f)

    emails = data.get("emails", [])

    # The initial mailbox has emails with id 1–26 (pre-populated before the agent runs).
    # Any email with id >= 27 was sent by the agent during the task.
    # We identify agent-sent emails by email_id > 26, then verify they are from leaves@.
    INITIAL_EMAIL_THRESHOLD = 26

    agent_sent = []
    for e in emails:
        eid = e.get("email_id")
        if eid is None:
            continue
        try:
            eid_int = int(eid)
        except (ValueError, TypeError):
            continue
        if eid_int <= INITIAL_EMAIL_THRESHOLD:
            continue
        from_addr = (e.get("from_addr") or e.get("from") or "").strip().lower()
        if from_addr == "leaves@ridgelinegear.com":
            agent_sent.append(e)

    if not agent_sent:
        any_outgoing = [e for e in emails if
                        (e.get("from_addr") or "").strip().lower() == "leaves@ridgelinegear.com"]
        agent_ids = [(e.get("email_id"), e.get("date", "no date")) for e in any_outgoing if
                     (e.get("email_id") or 0) > INITIAL_EMAIL_THRESHOLD]
        return {"pass": False, "score": 0.0,
                "feedback": f"No agent-sent emails (id > {INITIAL_EMAIL_THRESHOLD}) from leaves@ridgelinegear.com found. "
                            f"Found {len(any_outgoing)} total outgoing email(s) from leaves@. "
                            f"Agent-id candidates: {agent_ids}"}

    CLAIRE_TERMS = {"claire", "ndubisi"}
    GREG_TERMS   = {"greg", "ostrowski"}

    eligibility_emails = []
    manager_emails     = []
    extra_emails       = []

    for e in agent_sent:
        to_addr = (e.get("to_addr") or e.get("to") or "").strip().lower()
        to_claire = any(t in to_addr for t in CLAIRE_TERMS)
        to_greg   = any(t in to_addr for t in GREG_TERMS)

        if to_claire and not to_greg:
            eligibility_emails.append(e)
        elif to_greg and not to_claire:
            manager_emails.append(e)
        else:
            extra_emails.append(e)

    found_eligibility = len(eligibility_emails) > 0
    found_manager     = len(manager_emails) > 0

    # More than one email to the same permitted recipient = extra
    extra_claire = eligibility_emails[1:]
    extra_greg   = manager_emails[1:]
    all_extras   = extra_emails + extra_claire + extra_greg

    feedback_parts = [f"Agent-sent emails (id > {INITIAL_EMAIL_THRESHOLD}) from leaves@ridgelinegear.com: {len(agent_sent)}."]
    score = 0.0

    if found_eligibility:
        e = eligibility_emails[0]
        feedback_parts.append(f"FOUND: Eligibility notice to Claire (id={e.get('email_id')}, folder='{e.get('folder')}').")
        score += 0.40
    else:
        feedback_parts.append("MISSING: No outgoing email to Claire.")

    if found_manager:
        e = manager_emails[0]
        feedback_parts.append(f"FOUND: Manager notification to Greg Ostrowski (id={e.get('email_id')}, folder='{e.get('folder')}').")
        score += 0.40
    else:
        feedback_parts.append("MISSING: No outgoing email to Greg Ostrowski.")

    if not all_extras:
        feedback_parts.append("No extra/unsolicited outgoing emails.")
        score += 0.20
    else:
        descs = [f"id={ex.get('email_id')}, To: {ex.get('to_addr', '?')}, Subject: {ex.get('subject', '?')}" for ex in all_extras]
        feedback_parts.append(f"EXTRA EMAILS ({len(all_extras)}) not permitted by SOP: " + "; ".join(descs))

    passed = found_eligibility and found_manager and not all_extras

    return {
        "pass":     passed,
        "score":    round(min(score, 1.0), 2),
        "feedback": " ".join(feedback_parts),
    }

from pathlib import Path
import openpyxl
import re

def verify(workspace_path, external_services_path=None):
    file_path = Path(workspace_path) / "leave_tracker.xlsx"
    if not file_path.exists():
        return {"pass": False, "score": 0.0, "feedback": f"File not found: {file_path}"}

    wb = openpyxl.load_workbook(str(file_path), data_only=True)
    ws = wb.active

    # Find the row with LC-2026-0050
    target_row = None
    for row in ws.iter_rows(min_row=1, max_row=ws.max_row):
        for cell in row:
            if cell.value is not None and str(cell.value).strip() == "LC-2026-0050":
                target_row = cell.row
                break
        if target_row:
            break

    if target_row is None:
        return {"pass": False, "score": 0.0, "feedback": "Could not find row with case LC-2026-0050 in leave_tracker.xlsx"}

    # Expected values by column index (1-based)
    # Columns: A=1, B=2, C=3, D=4, E=5, F=6, G=7(blank), H=8, I=9, J=10, K=11, L=12(blank),
    #          M=13, N=14, O=15, P=16, Q=17, R=18, S=19, T=20, U=21, V=22(blank), W=23(blank), X=24(blank), Y=25(blank)
    expected = {
        1: "LC-2026-0050",
        2: "E-04471",
        3: "Claire Ndubisi",
        4: "FMLA + FAMLI",
        5: "04/14/2026",
        6: "05/26/2026",
        7: None,  # blank
        8: "Continuous",
        9: 0,
        10: 480,
        11: "Not Yet Requested",
        12: None,  # blank
        13: "Not Yet",
        14: "P3",
        15: "Intake \u2014 Pending Info",  # em-dash
        16: "N",
        17: "N",
        18: "Yes",
        19: "Pending",
        20: "Request received 04/09/2026 08:47 MT. Reason: family member (mother) serious health condition. Leave type: continuous. Foreseeable: No. Manager: Greg Ostrowski. Contact preference: work email. Status: not yet actioned.",
        21: "04/09/2026",
        22: None,
        23: None,
        24: None,
        25: None,
    }

    def normalize(val):
        if val is None:
            return None
        # Handle dates
        if hasattr(val, 'strftime'):
            return val.strftime('%m/%d/%Y')
        s = str(val).strip()
        if s == '' or s.lower() == 'none':
            return None
        return s

    def values_match(actual, expected_val):
        a = normalize(actual)
        e = normalize(expected_val)
        # Both blank
        if a is None and e is None:
            return True
        if a is None or e is None:
            return False
        # Try numeric comparison
        try:
            a_num = float(a)
            e_num = float(e)
            if e_num == 0:
                return abs(a_num) < 0.01
            return abs(a_num - e_num) / max(abs(e_num), 1e-9) < 0.05
        except (ValueError, TypeError):
            pass
        # String comparison (case-insensitive for short values, exact for long ones)
        return a.lower() == e.lower() or a == e

    mismatches = []
    for col_idx, exp_val in expected.items():
        actual_val = ws.cell(row=target_row, column=col_idx).value
        if not values_match(actual_val, exp_val):
            mismatches.append(f"Column {col_idx}: expected {repr(normalize(exp_val))}, got {repr(normalize(actual_val))}")

    if not mismatches:
        return {"pass": True, "score": 1.0, "feedback": f"Row for LC-2026-0050 (row {target_row}) matches expected initial state across all columns."}
    else:
        detail = "; ".join(mismatches)
        return {"pass": False, "score": 0.0, "feedback": f"Row for LC-2026-0050 has mismatches: {detail}"}
